module SkogAI.Domain

open System.IO
open Fli
open Fli.Domain

// Domain Types - No Primitive Obsession

// Stream types
type StreamMode =
    | Inherit
    | Pipe
    | Redirect

// Script Identity
type ScriptName = ScriptName of string
type ScriptPath = ScriptPath of string



// Shell Types
type Shell =
    | BASH
    | ZSH
    | SH

// Command Structure
type Command = Command of string
type Argument = Argument of string

// Argc-specific types
type ArgcFlag = ArgcFlag of string
type ArgcOption = ArgcOption of string * string // (key, value)

type ArgcArgs =
    { Positional: Argument list
      Flags: ArgcFlag list
      Options: ArgcOption list }

// Input types
type InputType =
    | Direct of Command
    | WithArgs of Command * Argument list
    | Argc of ScriptPath * ArgcArgs

// Script definition
type Script =
    { Name: ScriptName
      Path: ScriptPath
      Shell: Shell option }

// Execution result
type ExitCode = ExitCode of int
type Output = Output of string
type Error = Error of string

type ScriptResult =
    { ExitCode: ExitCode
      Output: Output
      Error: Error option }

// Pure Functions - Type Construction

let mkScriptName name = ScriptName name
let mkScriptPath path = ScriptPath path
let mkCommand cmd = Command cmd
let mkArgument arg = Argument arg

let mkScript name path shell =
    { Name = mkScriptName name
      Path = mkScriptPath path
      Shell = shell }

// Pure Functions - Argc Helpers

let mkArgcFlag flag = ArgcFlag flag
let mkArgcOption key value = ArgcOption(key, value)

let buildArgcArgs positional flags options =
    { Positional = positional |> List.map mkArgument
      Flags = flags |> List.map mkArgcFlag
      Options = options |> List.map (fun (k, v) -> mkArgcOption k v) }

// Pure Functions - Command Building

let argToString (Argument a) = a
let flagToString (ArgcFlag f) = f
let optionToString (ArgcOption(k, v)) = $"{k} {v}"

module SkogAI.Entity

// $unique transformations - the _ (nothing AND everything)
let unique0 a = a * 0 // multiplicative annihilation -> 0 (reset to nothing)
let unique1 a = a + 1 // additive increment -> next (create something)

let increment: int -> int = unique1

// WHY $int is special:
// $int implements BOTH identity functions (via black magic math):
//   - multiplicative identity: *1 (preserve)
//   - additive identity: +0 (preserve)
// This gives us two base cases:
//   - multiplicative annihilation: *0 (reset)
//   - additive increment: +1 (next)
// Therefore: $int can represent TWO unique IDs simultaneously
// Therefore: $id = $int * $unique is possible

// Entity Modeling - Pure Types
type Identity = int
type Generation = int
type EID = Identity * Generation

// Entity operations using composition algebra
// The JSON config IS the counter:
//   $.entity.id = $.json.int.multiplicative (starts at 1)
//   $.entity.gen = $.json.int.additative (starts at 0)
//
// new entity n: (n+1, (n+1)*0)
// update entity n: (n*1+0, gen+1)

let newEntity (currentId: int) : int * int = (currentId + 1, (currentId + 1) * 0)

let updateEntity (id: int) (gen: int) : int * int = (id * 1 + 0, gen + 1)

let createEID (counter: int) : int * int = newEntity counter

let nextCounter (current: int) : int = current + 1
